import json
import pandas as pd
from datetime import datetime

with open(locals()['var_function-call-1518981953904716875'], 'r') as f:
    cases = json.load(f)
with open(locals()['var_function-call-4271949275430875243'], 'r') as f:
    history = json.load(f)

# 1. Calculate Global Processed Count
all_case_owners = {}
all_case_ids = set(c['id'] for c in cases)

# Initialize with ownerid
for c in cases:
    cid = c['id']
    all_case_owners[cid] = set()
    if c.get('ownerid'):
        all_case_owners[cid].add(c['ownerid'])

# Add history
for h in history:
    cid = h.get('caseid__c')
    if cid in all_case_ids:
        owner = h.get('newvalue__c')
        if owner:
            all_case_owners[cid].add(owner)
        old = h.get('oldvalue__c')
        if old and old != "None":
            all_case_owners[cid].add(old)

global_processed_count = {}
for cid, owners in all_case_owners.items():
    for agent in owners:
        global_processed_count[agent] = global_processed_count.get(agent, 0) + 1

# 2. Identify Eligible Agents (Count > 1)
eligible_agents = set(a for a, c in global_processed_count.items() if c > 1)

# 3. Calculate Window HT
def parse_date(d):
    if not d: return None
    try:
        return datetime.strptime(d.split('.')[0], "%Y-%m-%dT%H:%M:%S")
    except:
        return None

start_date = datetime(2023, 5, 2)
end_date = datetime(2023, 9, 2, 23, 59, 59)

window_ht_sum = {}
window_ht_count = {}

for c in cases:
    closed = parse_date(c.get('closeddate'))
    created = parse_date(c.get('createddate'))
    if closed and start_date <= closed <= end_date:
        ht = (closed - created).total_seconds()

        # Check owners for THIS case (to determine if transferred)
        # We need to know if THIS case was transferred. 
        # "Transferred" means > 1 owner in its history.
        # We have owners in all_case_owners[c['id']]
        owners = all_case_owners[c['id']]

        if len(owners) == 1:
            agent = list(owners)[0]
            # Check if agent is eligible (global count > 1)
            if agent in eligible_agents:
                window_ht_sum[agent] = window_ht_sum.get(agent, 0.0) + ht
                window_ht_count[agent] = window_ht_count.get(agent, 0) + 1

results = []
for agent, count in window_ht_count.items():
    avg = window_ht_sum[agent] / count
    results.append({'agent': agent, 'avg_ht': avg, 'count': count})

if results:
    results.sort(key=lambda x: x['avg_ht'])
    print("__RESULT__:")
    print(json.dumps(results[0]['agent']))
else:
    print("__RESULT__:")
    print(json.dumps("No eligible agents"))

